module top_module(
    input clk,
    input rst,
    output reg [2:0] out
);reg [2:0] cnt;

always @(posedge clk) begin
    if (rst) begin
        cnt <= 3'b0;
    end else if (cnt == 3'b111) begin
        cnt <= 3'b0;
    end else begin
        cnt <= cnt + 1;
    end
end

assign out = cnt;

endmodule
